def solve(vals, key):
    class TreeNode:
        def __init__(self, v): self.val = v; self.left = self.right = None
    def build(arr):
        if not arr or arr[0] == 'null': return None
        root = TreeNode(int(arr[0]))
        q = [root]; i = 1
        while q and i < len(arr):
            node = q.pop(0)
            if i < len(arr) and arr[i] != 'null':
                node.left = TreeNode(int(arr[i])); q.append(node.left)
            i += 1
            if i < len(arr) and arr[i] != 'null':
                node.right = TreeNode(int(arr[i])); q.append(node.right)
            i += 1
        return root
    def deleteNode(root, key):
        if not root: return None
        if key < root.val: root.left = deleteNode(root.left, key)
        elif key > root.val: root.right = deleteNode(root.right, key)
        else:
            if not root.left: return root.right
            if not root.right: return root.left
            m = root.right
            while m.left: m = m.left
            root.val = m.val
            root.right = deleteNode(root.right, m.val)
        return root
    def serialize(root):
        if not root: return '[]'
        q = [root]; res = []
        while q:
            node = q.pop(0)
            if node:
                res.append(str(node.val))
                q.append(node.left); q.append(node.right)
            else: res.append('null')
        while res and res[-1] == 'null': res.pop()
        return '[' + ', '.join(res) + ']'
    root = build(vals.split())
    return serialize(deleteNode(root, int(key)))

